import React, { useEffect, useRef, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getChannel } from '../services/api';
import Hls from 'hls.js';

const ChannelPlayer = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const hlsRef = useRef(null);
  const [channel, setChannel] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadChannel();
    return () => {
      if (hlsRef.current) {
        hlsRef.current.destroy();
        hlsRef.current = null;
      }
    };
  }, [id]);

  const loadChannel = async () => {
    try {
      const data = await getChannel(id);
      setChannel(data);
      setTimeout(() => loadVideo(data.stream_url), 500);
    } catch (err) {
      setError('Canal no encontrado');
    } finally {
      setLoading(false);
    }
  };

  const loadVideo = (url) => {
    const video = videoRef.current;
    if (!video) return;

    // Destruir instancia anterior
    if (hlsRef.current) {
      hlsRef.current.destroy();
      hlsRef.current = null;
    }

    const isM3U8 = url.includes('.m3u8') || url.includes('.ts');

    if (isM3U8 && Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true,
        lowLatencyMode: true,
        backBufferLength: 90,
        xhrSetup: (xhr) => {
          xhr.withCredentials = false;
        }
      });

      hls.loadSource(url);
      hls.attachMedia(video);

      hls.on(Hls.Events.MANIFEST_PARSED, () => {
        video.play().catch(() => {});
      });

      hls.on(Hls.Events.ERROR, (event, data) => {
        if (data.fatal) {
          console.error('HLS error fatal:', data);
          setError('No se puede reproducir este canal');
        }
      });

      hlsRef.current = hls;

    } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
      // Safari nativo
      video.src = url;
      video.play().catch(() => {});
    } else {
      // MP4 u otros formatos directos
      video.src = url;
      video.play().catch(() => {});
    }
  };

  if (loading) return <div className="p-4 text-white">Cargando canal...</div>;
  if (error) return (
    <div className="p-4 text-white">
      <div className="text-red-400 mb-4">{error}</div>
      <Link to="/" className="bg-red-600 hover:bg-red-700 px-4 py-2 rounded">Volver</Link>
    </div>
  );

  return (
    <div className="bg-black min-h-screen">
      {/* Header */}
      <div className="p-4 bg-gray-900 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {channel.logo && (
            <img src={channel.logo} alt={channel.name} className="w-12 h-12 object-contain bg-white rounded p-1" onError={(e) => e.target.style.display = 'none'} />
          )}
          <div>
            <h1 className="text-white text-xl font-bold">{channel.name}</h1>
            <p className="text-gray-400 text-sm">{channel.country} • {channel.category}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <Link to="/" className="bg-gray-700 hover:bg-gray-600 px-4 py-2 rounded text-white text-sm">← Volver</Link>
          <button onClick={() => window.open(channel.stream_url, '_blank')} className="bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded text-white text-sm">
            Abrir Directo
          </button>
        </div>
      </div>

      {/* Video */}
      <div className="w-full bg-black">
        <video
          ref={videoRef}
          className="w-full h-auto max-h-[70vh]"
          controls
          playsInline
          style={{ background: '#000' }}
        />
      </div>

      {/* Info */}
      <div className="px-4 py-3 bg-gray-900">
        <span className="bg-red-600 text-white px-2 py-1 rounded text-xs mr-2">EN VIVO</span>
        <span className="text-gray-400 text-xs">{channel.stream_url}</span>
      </div>
    </div>
  );
};

export default ChannelPlayer;
